```html
<!DOCTYPE html>
<html lang="zh">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>贪吃蛇</title>
<style>
body {
margin: 0;
background: #1a1a1a;
display: flex;
justify-content: center;
align-items: center;
height: 100vh;
font-family: monospace;
}
#game {
display: flex;
flex-direction: column;
align-items: center;
}
canvas {
background: #2d2d2d;
border: 2px solid #5c5c5c;
}
#info {
color: #ccc;
font-size: 18px;
margin-top: 10px;
}
</style>
</head>
<body>
<div id="game">
<canvas id="snakeCanvas" width="400" height="400"></canvas>
<div id="info">得分: 0</div>
</div>

<script>
({
const canvas = document.;
const ctx = canvas.;

// 网格设置
const gridSize = 20;          // 每个格子像素
const cols = canvas.width / gridSize;   // 20
const rows = canvas.height / gridSize;  // 20

// 方向常量
const Dir = { UP: 'UP', DOWN: 'DOWN', LEFT: 'LEFT', RIGHT: 'RIGHT' };

// 初始状态
let snake = [
{ x: 10, y: 10 },
{ x: 9, y: 10 },
{ x: 8, y: 10 }
];
let food = { x: 15, y: 10 };
let direction = Dir.RIGHT;
let nextDirection = Dir.RIGHT;
let score = 0;
let gameOver = false;
let gameLoopInterval = null;
const speed = 100; // 毫秒

// 生成随机食物位置（避免在蛇身上）
function {
const allPositions = [];
for (let y = 0; y < rows; y++) {
for (let x = 0; x < cols; x++) {
if (!snake.) {
allPositions.;
}
}
}
if (allPositions.length === 0) return null; // 满了，胜利
const idx = Math.;
return allPositions[idx];
}

// 重置游戏
function {
snake = [
{ x: 10, y: 10 },
{ x: 9, y: 10 },
{ x: 8, y: 10 }
];
direction = Dir.RIGHT;
nextDirection = Dir.RIGHT;
score = 0;
gameOver = false;
food = { x: 15, y: 10 }; // 固定初始食物
document..textContent = `得分: ${score}`;
if (gameLoopInterval) ;
gameLoopInterval = ;
}

// 绘制
function {
// 清空
ctx.fillStyle = '#2d2d2d';
ctx.;

// 画食物
ctx.fillStyle = '#ff5555';
ctx.;

// 画蛇
snake.forEach((seg, index) => {
ctx.fillStyle = index === 0 ? '#50fa7b' : '#8be9fd';
ctx.;
});

// 游戏结束遮罩
if (gameOver) {
ctx.fillStyle = '';
ctx.;
ctx.fillStyle = '#f8f8f2';
ctx.font = '26px monospace';
ctx.textAlign = 'center';
ctx.;
ctx.font = '16px monospace';
ctx.;
}
}

// 移动逻辑
function {
if (gameOver) return;

// 更新方向（防止反向）
if ((direction === Dir.UP && nextDirection !== Dir.DOWN) ||
(direction === Dir.DOWN && nextDirection !== Dir.UP) ||
(direction === Dir.LEFT && nextDirection !== Dir.RIGHT) ||
(direction === Dir.RIGHT && nextDirection !== Dir.LEFT)) {
direction = nextDirection;
}

const head = snake[0];
let newHead = { ...head };

switch (direction) {
case Dir.UP:    newHead.y -= 1; break;
case Dir.DOWN:  newHead.y += 1; break;
case Dir.LEFT:  newHead.x -= 1; break;
case Dir.RIGHT: newHead.x += 1; break;
}

// 边界碰撞检测
if (newHead.x < 0 || newHead.x >= cols || newHead.y < 0 || newHead.y >= rows) {
gameOver = true;
;
gameLoopInterval = null;
;
return;
}

// 自身碰撞检测（排除尾部，因为尾部会离开）
if (snake.some((seg, idx) => idx !== 0 && seg.x === newHead.x && seg.y === newHead.y)) {
gameOver = true;
;
gameLoopInterval = null;
;
return;
}

// 插入新头
snake.;

// 检查是否吃到食物
if (newHead.x === food.x && newHead.y === food.y) {
score++;
document..textContent = `得分: ${score}`;
const newFood = ;
if (newFood) {
food = newFood;
} else {
// 蛇已经占满所有格子，玩家胜利
gameOver = true;
;
gameLoopInterval = null;
;
return;
}
} else {
// 没吃到移除尾
snake.;
}
}

function {
;
;
}

// 键盘监听
window.addEventListener('keydown', (e) => {
// 防止滚动和默认行为
const key = e.key;
if (['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight', ' '].) {
e.;
}

if (gameOver) {
if (key === ' ') {
;
}
return;
}

switch (key) {
case 'ArrowUp':
nextDirection = Dir.UP;
break;
case 'ArrowDown':
nextDirection = Dir.DOWN;
break;
case 'ArrowLeft':
nextDirection = Dir.LEFT;
break;
case 'ArrowRight':
nextDirection = Dir.RIGHT;
break;
case ' ':
// 空格也可以做暂停/重启，这里只用于游戏结束，非结束状态不处理
break;
default:
break;
}
});

// 启动游戏
;
})();
</script>
</body>
</html>

### 怎么用
1. 把上面全部内容复制到文本编辑器，保存为 `贪吃蛇.html`。
2. 双击用浏览器打开。
3. 键盘 ↑ ↓ ← → 控制方向，碰到墙壁或自己身体就结束。
4. 结束后按空格键重新开始。

分数会实时显示在画布下方，速度已经调成适合操作的节奏。如果需要调快或调慢，可以修改代码里的 `speed` 变量（单位毫秒，越小越快）。

